#include "ReuseRepresentationVerifier.h"
#include "../81_Spiral2Contracts/Spiral2Contracts.h"
#include <span>
#include <string_view>
namespace sge4_5::spiral3::verification
{
namespace
{
base::Digest256 Lit(std::string_view v){return base::Sha256(std::as_bytes(std::span(v.data(),v.size())));}constexpr std::uint32_t Groups(std::uint32_t c){return(c+63u)/64u;}
base::Digest256 IndependentProgram(candidate::OperationKindV1 op){using O=candidate::OperationKindV1;switch(op){case O::DynamicInvocationSource:return Lit("S3.L0.DynamicInvocationSource.V1");case O::ConsumerPointSource:return Lit("S3.L1.ConsumerPointSource.V1");case O::LocalMotorToMatrix:return Lit("S3.A0.LocalMotorToMatrix.V1");case O::MatrixHierarchy:return Lit("S3.A1.MatrixHierarchy.SerialCanonicalOrder.V1");case O::MatrixConsumerApply:return Lit("S3.MatrixConsumerApply.V1");case O::MotorHierarchy:return Lit("S3.MotorHierarchy.SerialCanonicalOrder.V1");case O::DirectPgaConsumerApply:return Lit("S3.B1.DirectPgaConsumerApply.V1");case O::GlobalMotorToMatrix:return Lit("S3.C1.GlobalMotorToMatrix.V1");default:return {};}}
VerifiedReuseOperationV1 Make(std::uint32_t ordinal,candidate::OperationKindV1 op,std::uint32_t inStride,std::uint32_t inCount,std::uint32_t outStride,std::uint32_t outCount,std::uint32_t dispatch,std::uint32_t secondStride=0,std::uint32_t secondCount=0){VerifiedReuseOperationV1 v;v.ordinal=ordinal;v.operation=op;v.primaryInputStride=inStride;v.primaryInputElementCount=inCount;v.primaryOutputStride=outStride;v.primaryOutputElementCount=outCount;v.secondaryInputStride=secondStride;v.secondaryInputElementCount=secondCount;v.secondaryOutputStride=secondStride;v.secondaryOutputElementCount=secondCount;v.dispatchX=dispatch;v.programIdentity=IndependentProgram(op);v.operationIdentity=base::Sha256(SerializeVerifiedReuseOperationV1(v));return v;}
base::Result<VerifiedReuseExecutionPlanV1,std::string> Derive(const spiral2::hierarchy::RigidHierarchySemanticV1&h,const semantic::ReuseSweepSemanticV1&s,candidate::CandidateKindV1 kind){auto valid=semantic::ValidateReuseSweepSemanticV1(h,s);if(!valid)return base::Result<VerifiedReuseExecutionPlanV1,std::string>::Failure(valid.Error());using O=candidate::OperationKindV1;using L=candidate::MatrixLoweringPositionV1;VerifiedReuseExecutionPlanV1 p;p.reuseSemanticIdentity=semantic::ReuseSweepSemanticIdentityV1(s);p.hierarchySemanticIdentity=s.hierarchySemanticIdentity;p.dynamicInvocationSchemaIdentity=spiral2::contracts::DynamicPaletteInvocationSchemaIdentityV1(spiral2::contracts::BuildDynamicPaletteInvocationSchemaV1(h));p.localPointCorpusIdentity=s.localPointCorpusIdentity;p.observationContractIdentity=s.observationContractIdentity;p.kind=kind;p.boneCount=s.boneCount;p.reuseCount=s.reuseCount;p.pointCount=s.pointCount;p.hierarchyDepthCount=static_cast<std::uint32_t>(h.depthOffsets.size()-1);p.hierarchyExecutionModel=candidate::HierarchyExecutionModelV1::SingleDispatchCanonicalOrderSerial;p.commonSourceDispatchCount=2;auto add=[&](O op,std::uint32_t is,std::uint32_t ic,std::uint32_t os,std::uint32_t oc,std::uint32_t d,std::uint32_t ss=0,std::uint32_t sc=0){p.operations.push_back(Make(static_cast<std::uint32_t>(p.operations.size()),op,is,ic,os,oc,d,ss,sc));return static_cast<std::uint32_t>(p.operations.size()-1);};const auto dynamic=add(O::DynamicInvocationSource,32,s.boneCount,32,s.boneCount,Groups(s.pointCount),16,s.pointCount);const auto points=add(O::ConsumerPointSource,0,0,16,s.pointCount,Groups(s.pointCount));auto edge=[&](std::uint32_t a,std::uint32_t b){p.edges.push_back({a,b});};switch(kind){case candidate::CandidateKindV1::MatrixHierarchy:{const auto a=add(O::LocalMotorToMatrix,32,s.boneCount,48,s.boneCount,Groups(s.boneCount));const auto b=add(O::MatrixHierarchy,48,s.boneCount,48,s.boneCount,1);const auto c=add(O::MatrixConsumerApply,48,s.boneCount,16,s.pointCount,Groups(s.pointCount),16,s.pointCount);edge(dynamic,a);edge(a,b);edge(b,c);edge(points,c);p.loweringPosition=L::BeforeHierarchy;break;}case candidate::CandidateKindV1::DirectPgaHierarchy:{const auto a=add(O::MotorHierarchy,32,s.boneCount,32,s.boneCount,1);const auto b=add(O::DirectPgaConsumerApply,32,s.boneCount,16,s.pointCount,Groups(s.pointCount),16,s.pointCount);edge(dynamic,a);edge(a,b);edge(points,b);p.loweringPosition=L::Absent;break;}case candidate::CandidateKindV1::HybridHierarchy:{const auto a=add(O::MotorHierarchy,32,s.boneCount,32,s.boneCount,1);const auto b=add(O::GlobalMotorToMatrix,32,s.boneCount,48,s.boneCount,Groups(s.boneCount));const auto c=add(O::MatrixConsumerApply,48,s.boneCount,16,s.pointCount,Groups(s.pointCount),16,s.pointCount);edge(dynamic,a);edge(a,b);edge(b,c);edge(points,c);p.loweringPosition=L::AfterHierarchy;break;}default:return base::Result<VerifiedReuseExecutionPlanV1,std::string>::Failure("unknown candidate kind");}p.candidateLeafDispatchCount=static_cast<std::uint32_t>(p.operations.size())-p.commonSourceDispatchCount;p.planIdentity=base::Sha256(SerializeVerifiedReuseExecutionPlanV1(p));return base::Result<VerifiedReuseExecutionPlanV1,std::string>::Success(std::move(p));}
bool Same(const candidate::CandidateNodeV1&a,const VerifiedReuseOperationV1&b){return a.ordinal==b.ordinal&&a.operation==b.operation&&a.primaryInputStride==b.primaryInputStride&&a.primaryInputElementCount==b.primaryInputElementCount&&a.primaryOutputStride==b.primaryOutputStride&&a.primaryOutputElementCount==b.primaryOutputElementCount&&a.secondaryInputStride==b.secondaryInputStride&&a.secondaryInputElementCount==b.secondaryInputElementCount&&a.secondaryOutputStride==b.secondaryOutputStride&&a.secondaryOutputElementCount==b.secondaryOutputElementCount&&a.dispatchX==b.dispatchX&&a.dispatchY==b.dispatchY&&a.dispatchZ==b.dispatchZ&&a.programIdentity==b.programIdentity;}
}
std::vector<std::byte> SerializeVerifiedReuseOperationV1(const VerifiedReuseOperationV1&n){base::BinaryWriter w;w.WriteU32(n.ordinal);w.WriteU32(static_cast<std::uint32_t>(n.operation));w.WriteU32(n.primaryInputStride);w.WriteU32(n.primaryInputElementCount);w.WriteU32(n.primaryOutputStride);w.WriteU32(n.primaryOutputElementCount);w.WriteU32(n.secondaryInputStride);w.WriteU32(n.secondaryInputElementCount);w.WriteU32(n.secondaryOutputStride);w.WriteU32(n.secondaryOutputElementCount);w.WriteU32(n.dispatchX);w.WriteU32(n.dispatchY);w.WriteU32(n.dispatchZ);w.WriteU32(0);w.WriteBytes(n.programIdentity);return std::move(w).Take();}
std::vector<std::byte> SerializeVerifiedReuseExecutionPlanV1(const VerifiedReuseExecutionPlanV1&p){base::BinaryWriter w;w.WriteBytes(Lit("SGE4-5.Spiral3.VerifiedReuseExecutionPlan.V1"));w.WriteBytes(p.reuseSemanticIdentity);w.WriteBytes(p.hierarchySemanticIdentity);w.WriteBytes(p.dynamicInvocationSchemaIdentity);w.WriteBytes(p.localPointCorpusIdentity);w.WriteBytes(p.observationContractIdentity);w.WriteU32(static_cast<std::uint32_t>(p.kind));w.WriteU32(static_cast<std::uint32_t>(p.loweringPosition));w.WriteU32(static_cast<std::uint32_t>(p.hierarchyExecutionModel));w.WriteU32(p.boneCount);w.WriteU32(p.reuseCount);w.WriteU32(p.pointCount);w.WriteU32(p.hierarchyDepthCount);w.WriteU32(p.commonSourceDispatchCount);w.WriteU32(p.candidateLeafDispatchCount);w.WriteU32(static_cast<std::uint32_t>(p.operations.size()));w.WriteU32(static_cast<std::uint32_t>(p.edges.size()));for(const auto&n:p.operations){const auto bytes=SerializeVerifiedReuseOperationV1(n);w.WriteU32(static_cast<std::uint32_t>(bytes.size()));w.WriteBytes(bytes);w.WriteBytes(n.operationIdentity);}for(const auto&e:p.edges){w.WriteU32(e.source);w.WriteU32(e.destination);}return std::move(w).Take();}
base::Result<VerifiedReuseRepresentationV1,std::string> VerifyCandidateGraphV1(const spiral2::hierarchy::RigidHierarchySemanticV1&h,const semantic::ReuseSweepSemanticV1&s,const candidate::RawCandidateGraphV1&q){auto expected=Derive(h,s,q.kind);if(!expected)return base::Result<VerifiedReuseRepresentationV1,std::string>::Failure(expected.Error());const auto&p=expected.Value();if(q.reuseSemanticIdentity!=p.reuseSemanticIdentity||q.hierarchySemanticIdentity!=p.hierarchySemanticIdentity||q.dynamicInvocationSchemaIdentity!=p.dynamicInvocationSchemaIdentity||q.localPointCorpusIdentity!=p.localPointCorpusIdentity||q.observationContractIdentity!=p.observationContractIdentity)return base::Result<VerifiedReuseRepresentationV1,std::string>::Failure("semantic, corpus, invocation, or observation identity mismatch");if(q.boneCount!=p.boneCount||q.reuseCount!=p.reuseCount||q.pointCount!=p.pointCount)return base::Result<VerifiedReuseRepresentationV1,std::string>::Failure("workload dimensions mismatch");if(q.proposedLoweringPosition!=p.loweringPosition||q.proposedHierarchyExecutionModel!=p.hierarchyExecutionModel||q.hierarchyDepthCount!=p.hierarchyDepthCount||q.commonSourceDispatchCount!=p.commonSourceDispatchCount||q.proposedCandidateLeafDispatchCount!=p.candidateLeafDispatchCount)return base::Result<VerifiedReuseRepresentationV1,std::string>::Failure("execution model or materialization decision mismatch");if(q.nodes.size()!=p.operations.size()||q.edges.size()!=p.edges.size())return base::Result<VerifiedReuseRepresentationV1,std::string>::Failure("candidate graph shape mismatch");for(std::size_t i=0;i<q.nodes.size();++i)if(!Same(q.nodes[i],p.operations[i]))return base::Result<VerifiedReuseRepresentationV1,std::string>::Failure("node execution decision mismatch");for(std::size_t i=0;i<q.edges.size();++i)if(q.edges[i].source!=p.edges[i].source||q.edges[i].destination!=p.edges[i].destination)return base::Result<VerifiedReuseRepresentationV1,std::string>::Failure("edge order mismatch");base::BinaryWriter w;w.WriteBytes(Lit("SGE4-5.Spiral3.VerifierCertificate.V1"));w.WriteBytes(p.planIdentity);w.WriteBytes(p.reuseSemanticIdentity);w.WriteU32(static_cast<std::uint32_t>(p.kind));w.WriteU32(p.reuseCount);w.WriteU32(p.candidateLeafDispatchCount);const auto cert=base::Sha256(std::move(w).Take());return base::Result<VerifiedReuseRepresentationV1,std::string>::Success(VerifiedReuseRepresentationV1(std::move(expected.Value()),cert));}
std::vector<std::byte> SerializeVerifiedReuseRepresentationV1(const VerifiedReuseRepresentationV1&v){base::BinaryWriter w;const auto plan=SerializeVerifiedReuseExecutionPlanV1(v.Plan());w.WriteBytes(Lit("SGE4-5.Spiral3.VerifiedReuseRepresentation.V1"));w.WriteU32(static_cast<std::uint32_t>(plan.size()));w.WriteBytes(plan);w.WriteBytes(v.Plan().planIdentity);w.WriteBytes(v.CertificateIdentity());return std::move(w).Take();}
}
